import React, { useState, useEffect } from 'react';
import MedicineSearch from '../components/MedicineSearch';
import DoseResult from '../components/DoseResult';
import AIChatBot from '../components/AIChatBot';
import { Alert, Spinner, Card } from '../components/UI';
import { api } from '../services/api';
import toast from 'react-hot-toast';

export default function CalculatorPage() {
  const [selectedMed, setSelectedMed] = useState(null);
  const [weight, setWeight] = useState('');
  const [ageYears, setAgeYears] = useState('');
  const [ageMonths, setAgeMonths] = useState('');
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(false);
  const [aiSuggestion, setAiSuggestion] = useState(null);
  const [dbStatus, setDbStatus] = useState(null);
  const [medicineCount, setMedicineCount] = useState(0);

  useEffect(() => {
    // Check database connection
    const checkDatabase = async () => {
      try {
        const stats = await api.getMedicineStats();
        setMedicineCount(stats.totalMedicines);
        setDbStatus('connected');
        toast.success(`Connected to database with ${stats.totalMedicines} medicines`);
      } catch (err) {
        console.error('Database connection error:', err);
        setDbStatus('error');
        toast.error('Cannot connect to database. Please check if backend server is running.');
      }
    };
    checkDatabase();
  }, []);

  const totalMonths = () => (parseFloat(ageYears) || 0) * 12 + (parseFloat(ageMonths) || 0);

  const handleCalculate = async () => {
    if (!selectedMed) {
      toast.error('Please select a medicine from the search dropdown');
      return;
    }
    if (!weight) {
      toast.error('Please enter weight');
      return;
    }
    
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const data = await api.calculateDose({
        medicine_id: selectedMed.id,
        weight_kg: parseFloat(weight),
        age_months: totalMonths() || 1,
      });
      setResult(data);
      toast.success('Dose calculated successfully!');
    } catch (err) {
      setError(err.response?.data?.error || err.message);
      toast.error('Failed to calculate dose');
    } finally {
      setLoading(false);
    }
  };

  const handleAISuggestion = (suggestion) => {
    setAiSuggestion(suggestion);
    if (suggestion.medicine) {
      setSelectedMed(suggestion.medicine);
      toast.success('AI suggestion applied!');
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-4">
      {/* Database Status Banner */}
      {dbStatus === 'connected' && (
        <div className="mb-6 p-4 bg-green-50 dark:bg-green-900/20 border-l-4 border-green-500 rounded-lg shadow-sm">
          <div className="flex items-center">
            <svg className="h-5 w-5 text-green-500 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            <p className="text-sm text-green-700 dark:text-green-300 font-medium">
              ✅ Database connected successfully with {medicineCount} medicines available
            </p>
          </div>
        </div>
      )}
      
      {dbStatus === 'error' && (
        <div className="mb-6 p-4 bg-red-50 dark:bg-red-900/20 border-l-4 border-red-500 rounded-lg shadow-sm">
          <div className="flex items-center">
            <svg className="h-5 w-5 text-red-500 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            <p className="text-sm text-red-700 dark:text-red-300 font-medium">
              ⚠️ Cannot connect to database. Please make sure the backend server is running at http://localhost:5000
            </p>
          </div>
        </div>
      )}

      {/* Header */}
      <div className="mb-10 text-center">
        <h1 className="text-5xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent mb-4">
          AI-Powered Dose Calculator
        </h1>
        <p className="text-lg text-gray-600 dark:text-gray-400 max-w-2xl mx-auto">
          Smart dosing with predictive analytics and clinical intelligence
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column - AI Chat */}
        <div className="lg:col-span-1">
          <div className="sticky top-24">
            <Card className="overflow-hidden shadow-xl">
              <div className="bg-gradient-to-r from-blue-500 to-purple-600 p-4">
                <div className="flex items-center space-x-2">
                  <svg className="h-6 w-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
                  </svg>
                  <h3 className="text-white font-semibold text-lg">AI Medical Assistant</h3>
                </div>
                <p className="text-white/80 text-sm mt-1">Ask me about doses or calculators</p>
              </div>
              <div className="h-[500px]">
                <AIChatBot onRecommendation={handleAISuggestion} />
              </div>
            </Card>
          </div>
        </div>

        {/* Right Column - Calculator */}
        <div className="lg:col-span-2">
          <Card className="shadow-xl overflow-hidden">
            <div className="bg-white dark:bg-gray-800 p-8">
              <div className="flex items-center space-x-2 mb-6">
                <svg className="h-6 w-6 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
                <h2 className="text-2xl font-bold text-gray-900 dark:text-white">Medication Details</h2>
              </div>

              {aiSuggestion && (
                <div className="mb-6 p-4 bg-blue-50 dark:bg-blue-900/20 rounded-xl border-l-4 border-blue-500 shadow-sm">
                  <div className="flex justify-between items-start">
                    <div className="flex-1">
                      <div className="flex items-center space-x-2 mb-2">
                        <svg className="h-5 w-5 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
                        </svg>
                        <strong className="text-blue-800 dark:text-blue-300">🤖 AI Suggestion</strong>
                      </div>
                      <p className="text-sm text-gray-700 dark:text-gray-300">{aiSuggestion.reasoning || 'Based on patient input'}</p>
                    </div>
                    <button
                      className="ml-4 px-4 py-2 text-sm bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition shadow-sm"
                      onClick={() => {
                        if (aiSuggestion.medicine) {
                          setSelectedMed(aiSuggestion.medicine);
                        }
                      }}
                    >
                      Apply
                    </button>
                  </div>
                </div>
              )}

              <div className="space-y-6">
                {/* Medicine Search */}
                <div>
                  <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                    Medicine <span className="text-red-500">*</span>
                  </label>
                  <MedicineSearch
                    value={selectedMed}
                    onSelect={(med) => {
                      setSelectedMed(med);
                      setResult(null);
                      setError(null);
                      toast.success(`${med.name} selected`);
                    }}
                    placeholder="Type medicine name (e.g., paracetamol, ibuprofen)..."
                  />
                  <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
                    Start typing to search from {medicineCount} medicines
                  </p>
                </div>

                {/* Weight Input */}
                <div>
                  <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                    Weight (kg) <span className="text-red-500">*</span>
                  </label>
                  <input
                    className="w-full px-4 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none dark:bg-gray-800 dark:text-white transition"
                    type="number"
                    min="0.5"
                    step="0.1"
                    placeholder="e.g., 70"
                    value={weight}
                    onChange={(e) => setWeight(e.target.value)}
                  />
                </div>

                {/* Age Input */}
                <div>
                  <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                    Age
                  </label>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <input
                        className="w-full px-4 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none dark:bg-gray-800 dark:text-white transition"
                        type="number"
                        min="0"
                        placeholder="Years"
                        value={ageYears}
                        onChange={(e) => setAgeYears(e.target.value)}
                      />
                    </div>
                    <div>
                      <input
                        className="w-full px-4 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none dark:bg-gray-800 dark:text-white transition"
                        type="number"
                        min="0"
                        max="11"
                        placeholder="Months"
                        value={ageMonths}
                        onChange={(e) => setAgeMonths(e.target.value)}
                      />
                    </div>
                  </div>
                </div>

                {/* Calculate Button */}
                <button
                  className="w-full py-3 bg-gradient-to-r from-blue-500 to-purple-600 text-white font-semibold rounded-lg hover:from-blue-600 hover:to-purple-700 transition-all transform hover:scale-[1.02] disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:scale-100 shadow-md"
                  onClick={handleCalculate}
                  disabled={!selectedMed || !weight || loading || dbStatus === 'error'}
                >
                  {loading ? (
                    <div className="flex items-center justify-center space-x-2">
                      <Spinner />
                      <span>Calculating...</span>
                    </div>
                  ) : (
                    'Calculate Safe Dose →'
                  )}
                </button>

                {/* Error Message */}
                {error && (
                  <Alert type="danger" className="mt-4">
                    {error}
                  </Alert>
                )}
              </div>
            </div>
          </Card>

          {/* Dose Result */}
          {result && (
            <div className="mt-6 animate-fadeIn">
              <DoseResult result={result} />
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
